                {"swissGerman": "buech", "german": "buche", "explanation": "'buech' = 'buche'. To book."},
                {"swissGerman": "Ferienwohnig", "german": "Ferienwohnung", "explanation": "'Ferienwohnig' = 'Ferienwohnung'. '-ung' → '-ig'."},
