                {"swissGerman": "Rugge", "german": "Rücken", "explanation": "'Rugge' = 'Rücken'. Swiss form for back."},
                {"swissGerman": "ohni", "german": "ohne", "explanation": "'ohni' = 'ohne'. Swiss form."},
